import React from "react";
import "./Products.css"; // Make sure Products.css exists in src/pages/

// Example product data (replace with your images)
const sampleProducts = [
  { id: 1, name: "Product 1", image: "https://via.placeholder.com/150" },
  { id: 2, name: "Product 2", image: "https://via.placeholder.com/150" },
  { id: 3, name: "Product 3", image: "https://via.placeholder.com/150" },
  { id: 4, name: "Product 4", image: "https://via.placeholder.com/150" },
];

const ProductPage = ({ cartItems, setCartItems, title, productsData }) => {
  const products = productsData || sampleProducts;

  const handleQuantityChange = (id, delta) => {
    setCartItems(prev => {
      const newQty = (prev[id] || 0) + delta;
      return { ...prev, [id]: newQty < 0 ? 0 : newQty };
    });
  };

  return (
    <div className="products-container">
      <h2>{title}</h2>
      <div className="products-grid">
        {products.map(product => (
          <div key={product.id} className="product-card">
            <img src={product.image} alt={product.name} />
            <h3>{product.name}</h3>
            <div className="quantity-control">
              <button onClick={() => handleQuantityChange(product.id, -1)}>-</button>
              <span>{cartItems[product.id] || 0}</span>
              <button onClick={() => handleQuantityChange(product.id, 1)}>+</button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default ProductPage;
